/**
 * @summary Decode a Chorcha URL and save questions into a folder
 */
export const getDecodeToFolderUrl = () => {
  return `/api/chorcha/decode-to-folder`;
};

export const decodeToFolder = async (
  decodeToFolderInput: DecodeToFolderInput,
  options?: RequestInit,
): Promise<QuestionSet> => {
  return customFetch<QuestionSet>(getDecodeToFolderUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(decodeToFolderInput),
  });
};

export const getDecodeToFolderMutationOptions = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof decodeToFolder>>,
    TError,
    { data: BodyType<DecodeToFolderInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof decodeToFolder>>,
  TError,
  { data: BodyType<DecodeToFolderInput> },
  TContext
> => {
  const mutationKey = ["decodeToFolder"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof decodeToFolder>>,
    { data: BodyType<DecodeToFolderInput> }
  > = (props) => {
    const { data } = props ?? {};

    return decodeToFolder(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type DecodeToFolderMutationResult = NonNullable<
  Awaited<ReturnType<typeof decodeToFolder>>
>;
export type DecodeToFolderMutationBody = BodyType<DecodeToFolderInput>;
export type DecodeToFolderMutationError = ErrorType<ErrorResponse>;

